const config = {
  "previewFeatures": [],
  "clientVersion": "7.7.0",
  "engineVersion": "75cbdc1eb7150937890ad5465d861175c6624711",
  "activeProvider": "postgresql",
  "inlineSchema": "generator client {\n  provider = \"prisma-client-js\"\n  output   = \"../lib/generated/prisma\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n}\n\n// ─── Auth ─────────────────────────────────────────────────────────────────────\n\nmodel User {\n  id            String          @id @default(uuid())\n  email         String          @unique\n  name          String?\n  image         String?\n  role          UserRole        @default(PLANNER)\n  emailVerified DateTime?\n  accounts      Account[]\n  sessions      Session[]\n  weddings      WeddingMember[]\n  createdAt     DateTime        @default(now())\n  updatedAt     DateTime        @updatedAt\n}\n\nmodel Account {\n  id                String  @id @default(uuid())\n  userId            String\n  type              String\n  provider          String\n  providerAccountId String\n  refresh_token     String? @db.Text\n  access_token      String? @db.Text\n  expires_at        Int?\n  token_type        String?\n  scope             String?\n  id_token          String? @db.Text\n  session_state     String?\n  user              User    @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  @@unique([provider, providerAccountId])\n}\n\nmodel Session {\n  id           String   @id @default(uuid())\n  sessionToken String   @unique\n  userId       String\n  expires      DateTime\n  user         User     @relation(fields: [userId], references: [id], onDelete: Cascade)\n}\n\nmodel VerificationToken {\n  identifier String\n  token      String   @unique\n  expires    DateTime\n\n  @@unique([identifier, token])\n}\n\nenum UserRole {\n  COUPLE\n  PLANNER\n  COMMITTEE\n  VENDOR\n  ADMIN\n}\n\n// ─── Wedding ──────────────────────────────────────────────────────────────────\n\nmodel Wedding {\n  id                 String       @id @default(uuid())\n  name               String\n  brideName          String?\n  groomName          String?\n  venue              String?\n  venueCapacity      Int?\n  budget             Decimal      @default(0)\n  currency           String       @default(\"KES\")\n  culturalType       CulturalType @default(STANDARD)\n  themeColor         String       @default(\"#8B5CF6\")\n  themeAccent        String       @default(\"#F59E0B\")\n  coverImagePath     String?\n  couplePhotoPath    String?\n  couplePhotoFocalX  Float        @default(50)\n  couplePhotoFocalY  Float        @default(50)\n  expectedGuestCount Int?\n  uninvitedBuffer    Int          @default(15)\n  palette            String[]     @default([])\n  setupComplete      Boolean      @default(false)\n\n  members               WeddingMember[]\n  events                WeddingEvent[]\n  guests                Guest[]\n  vendors               Vendor[]\n  payments              Payment[]\n  contributions         CommitteeContribution[]\n  // timelineEvents removed — replaced by EventProgramItem\n  checklistItems        ChecklistItem[]\n  budgetLines           BudgetLine[]\n  riskAlerts            RiskAlert[]\n  mediaItems            MediaItem[]\n  auditLogs             AuditLog[]\n  activityGroups        ActivityGroup[]\n  appointments          Appointment[]\n  dowryItems            DowryItem[]\n  attireItems           AttireItem[]\n  giftRegistryItems     GiftRegistryItem[]\n  giftsReceived         GiftReceived[]\n  transportRoutes       TransportRoute[]\n  accommodations        Accommodation[]\n  households            Household[]\n  paymentSchedules      PaymentSchedule[]\n  incidents             Incident[]\n  templateApplications  TemplateApplication[]\n  visionBoardCategories VisionBoardCategory[]\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n}\n\nmodel WeddingMember {\n  id                String   @id @default(uuid())\n  weddingId         String\n  userId            String\n  role              UserRole\n  canViewFinancials Boolean  @default(true)\n  wedding           Wedding  @relation(fields: [weddingId], references: [id], onDelete: Cascade)\n  user              User     @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  @@unique([weddingId, userId])\n  @@index([weddingId])\n}\n\nenum CulturalType {\n  STANDARD\n  KIKUYU\n  LUO\n  KAMBA\n  KALENJIN\n  COASTAL\n}\n\n// ─── Wedding Events (Traditional, Wedding, Post-wedding) ──────────────────────────\n\nmodel WeddingEvent {\n  id                String                  @id @default(uuid())\n  weddingId         String\n  name              String\n  type              EventType\n  date              DateTime\n  startTime         String?\n  endTime           String?\n  venue             String?\n  mapUrl            String?\n  description       String?\n  isMain            Boolean                 @default(false)\n  wedding           Wedding                 @relation(fields: [weddingId], references: [id], onDelete: Cascade)\n  guestAttendances  GuestEventAttendance[]\n  fromDependencies  EventDependency[]       @relation(\"FromEvent\")\n  toDependencies    EventDependency[]       @relation(\"ToEvent\")\n  honeymoonDays     HoneymoonDay[]\n  programItems      EventProgramItem[]\n  checklistItems    ChecklistItem[]\n  budgetLines       BudgetLine[]\n  appointments      Appointment[]\n  transportRoutes   TransportRoute[]\n  accommodations    Accommodation[]\n  giftRegistry      GiftRegistryItem[]\n  giftsReceived     GiftReceived[]\n  incidents         Incident[]\n  payments          Payment[]\n  contributions     CommitteeContribution[]\n  mediaItems        MediaItem[]\n  vendorAssignments VendorEventAssignment[]\n  contacts          EventContact[]\n  bridalTeamMembers BridalTeamMember[]\n  bridalRoleOutfits BridalRoleOutfit[]\n\n  @@index([weddingId, date])\n}\n\n// ─── Event Contacts ───────────────────────────────────────────────────────────\n\nmodel EventContact {\n  id        String       @id @default(uuid())\n  eventId   String\n  name      String\n  role      String?\n  phone     String?\n  email     String?\n  notes     String?\n  event     WeddingEvent @relation(fields: [eventId], references: [id], onDelete: Cascade)\n  createdAt DateTime     @default(now())\n  updatedAt DateTime     @updatedAt\n\n  @@index([eventId])\n}\n\n// ─── Event Program (ordered day-of activities) ────────────────────────────────\n\nmodel EventProgramItem {\n  id          String       @id @default(uuid())\n  eventId     String\n  title       String\n  description String?\n  date        DateTime? // null = single-day event; set for multi-day (honeymoon, moving)\n  startTime   String? // HH:mm\n  endTime     String? // HH:mm\n  duration    Int? // minutes\n  order       Int          @default(0)\n  assignedTo  String?\n  vendorId    String?\n  event       WeddingEvent @relation(fields: [eventId], references: [id], onDelete: Cascade)\n  createdAt   DateTime     @default(now())\n  updatedAt   DateTime     @updatedAt\n\n  @@index([eventId, order])\n  @@index([eventId, date])\n}\n\nenum EventType {\n  WEDDING\n  RECEPTION\n  POST_WEDDING\n  TRADITIONAL\n  CIVIL\n  ENGAGEMENT\n  AFTER_PARTY\n  HONEYMOON\n  MOVING\n}\n\n// ─── Bridal Team ──────────────────────────────────────────────────────────────\n\nmodel BridalTeamMember {\n  id                 String             @id @default(cuid())\n  eventId            String\n  name               String\n  role               BridalRole\n  side               BridalSide\n  phone              String?\n  email              String?\n  confirmationStatus ConfirmationStatus @default(PENDING)\n  notes              String?\n  deletedAt          DateTime?\n  event              WeddingEvent       @relation(fields: [eventId], references: [id], onDelete: Cascade)\n  createdAt          DateTime           @default(now())\n  updatedAt          DateTime           @updatedAt\n\n  @@index([eventId])\n}\n\nmodel BridalRoleOutfit {\n  id          String       @id @default(cuid())\n  eventId     String\n  role        BridalRole\n  title       String\n  description String?\n  event       WeddingEvent @relation(fields: [eventId], references: [id], onDelete: Cascade)\n  createdAt   DateTime     @default(now())\n  updatedAt   DateTime     @updatedAt\n\n  @@unique([eventId, role])\n  @@index([eventId])\n}\n\nenum BridalRole {\n  BRIDE\n  GROOM\n  BEST_MAN\n  MAID_OF_HONOUR\n  BRIDESMAID\n  GROOMSMAN\n  FLOWER_GIRL\n  PAGE_BOY\n  RING_BEARER\n  PARENT_BRIDE\n  PARENT_GROOM\n  NEGOTIATOR\n  ELDER\n  OTHER\n}\n\nenum BridalSide {\n  BRIDE\n  GROOM\n  BOTH\n}\n\nenum ConfirmationStatus {\n  PENDING\n  CONFIRMED\n  DECLINED\n}\n\n// ─── Event Dependencies ───────────────────────────────────────────────────────\n\nmodel EventDependency {\n  id          String       @id @default(uuid())\n  fromEventId String\n  toEventId   String\n  type        String\n  fromEvent   WeddingEvent @relation(\"FromEvent\", fields: [fromEventId], references: [id], onDelete: Cascade)\n  toEvent     WeddingEvent @relation(\"ToEvent\", fields: [toEventId], references: [id], onDelete: Cascade)\n\n  @@index([fromEventId])\n  @@index([toEventId])\n}\n\n// ─── Guest Event Attendance ───────────────────────────────────────────────────\n\nmodel GuestEventAttendance {\n  id          String       @id @default(uuid())\n  guestId     String\n  eventId     String\n  rsvpStatus  RsvpStatus   @default(PENDING)\n  checkedIn   Boolean      @default(false)\n  checkedInAt DateTime?\n  guest       Guest        @relation(fields: [guestId], references: [id], onDelete: Cascade)\n  event       WeddingEvent @relation(fields: [eventId], references: [id], onDelete: Cascade)\n\n  @@unique([guestId, eventId])\n  @@index([eventId])\n}\n\n// ─── Guests ───────────────────────────────────────────────────────────────────\n\nmodel Guest {\n  id             String        @id @default(uuid())\n  localId        String?\n  weddingId      String\n  name           String\n  phone          String?\n  email          String?\n  rsvpStatus     RsvpStatus    @default(PENDING)\n  committeeId    String?\n  side           GuestSide     @default(BOTH)\n  mealPref       String?\n  checkedIn      Boolean       @default(false)\n  checkedInAt    DateTime?\n  notes          String?\n  tags           String[]      @default([])\n  plusOneOf      String?\n  plusOneAllowed Boolean       @default(false)\n  priority       GuestPriority @default(GENERAL)\n  householdId    String?\n\n  version   Int       @default(1)\n  checksum  String    @default(\"\")\n  updatedBy String?\n  deletedAt DateTime?\n  deletedBy String?\n\n  wedding             Wedding                @relation(fields: [weddingId], references: [id], onDelete: Cascade)\n  household           Household?             @relation(fields: [householdId], references: [id])\n  eventAttendances    GuestEventAttendance[]\n  guestTransports     GuestTransport[]\n  guestAccommodations GuestAccommodation[]\n  giftsReceived       GiftReceived[]\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([weddingId, rsvpStatus])\n  @@index([weddingId, updatedAt])\n  @@index([committeeId, weddingId])\n  @@index([householdId])\n}\n\nenum GuestPriority {\n  VIP\n  GENERAL\n  OVERFLOW\n}\n\nenum RsvpStatus {\n  PENDING\n  CONFIRMED\n  DECLINED\n  MAYBE\n  WAITLISTED\n}\n\nenum GuestSide {\n  BRIDE\n  GROOM\n  BOTH\n}\n\n// ─── Household ────────────────────────────────────────────────────────────────\n\nmodel Household {\n  id        String  @id @default(uuid())\n  weddingId String\n  name      String\n  wedding   Wedding @relation(fields: [weddingId], references: [id], onDelete: Cascade)\n  guests    Guest[]\n\n  @@index([weddingId])\n}\n\n// ─── Vendors ──────────────────────────────────────────────────────────────────\n\nmodel Vendor {\n  id            String         @id @default(uuid())\n  weddingId     String\n  name          String\n  category      VendorCategory\n  status        VendorStatus   @default(ENQUIRED)\n  contactName   String?\n  contactPhone  String?\n  contactEmail  String?\n  amount        Decimal?\n  paidAmount    Decimal        @default(0)\n  depositAmount Decimal?\n  depositPaidAt DateTime?\n  contractPath  String?\n  lastContactAt DateTime?\n  notes         String?\n  description   String?\n  isBackup      Boolean        @default(false)\n  rating        Int?\n\n  version   Int       @default(1)\n  checksum  String    @default(\"\")\n  updatedBy String?\n  deletedAt DateTime?\n\n  wedding          Wedding                 @relation(fields: [weddingId], references: [id], onDelete: Cascade)\n  payments         Payment[]\n  vendorNotes      VendorNote[]\n  paymentSchedules PaymentSchedule[]\n  appointments     Appointment[]\n  transportRoutes  TransportRoute[]\n  attireItems      AttireItem[]\n  budgetLines      BudgetLine[]\n  eventAssignments VendorEventAssignment[]\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([weddingId, status])\n  @@index([weddingId, category])\n  @@index([weddingId, lastContactAt])\n}\n\n// ─── Vendor Event Assignment ──────────────────────────────────────────────────\n\nmodel VendorEventAssignment {\n  id       String  @id @default(uuid())\n  vendorId String\n  eventId  String\n  notes    String?\n\n  version   Int       @default(1)\n  checksum  String    @default(\"\")\n  updatedBy String?\n  deletedAt DateTime?\n  deletedBy String?\n\n  vendor    Vendor       @relation(fields: [vendorId], references: [id], onDelete: Cascade)\n  event     WeddingEvent @relation(fields: [eventId], references: [id], onDelete: Cascade)\n  createdAt DateTime     @default(now())\n  updatedAt DateTime     @updatedAt\n\n  @@unique([vendorId, eventId])\n  @@index([eventId])\n  @@index([vendorId])\n}\n\n// ─── Vendor Notes ─────────────────────────────────────────────────────────────\n\nmodel VendorNote {\n  id        String   @id @default(uuid())\n  vendorId  String\n  weddingId String\n  content   String\n  createdBy String\n  vendor    Vendor   @relation(fields: [vendorId], references: [id], onDelete: Cascade)\n  createdAt DateTime @default(now())\n\n  @@index([vendorId])\n}\n\n// ─── Payment Schedule ─────────────────────────────────────────────────────────\n\nmodel PaymentSchedule {\n  id        String   @id @default(uuid())\n  vendorId  String\n  weddingId String\n  dueDate   DateTime\n  amount    Decimal\n  isPaid    Boolean  @default(false)\n  vendor    Vendor   @relation(fields: [vendorId], references: [id], onDelete: Cascade)\n  wedding   Wedding  @relation(fields: [weddingId], references: [id], onDelete: Cascade)\n\n  @@index([weddingId, dueDate])\n  @@index([vendorId])\n}\n\nenum VendorCategory {\n  CATERING\n  PHOTOGRAPHY\n  VIDEOGRAPHY\n  FLORIST\n  MUSIC_DJ\n  BAND\n  TRANSPORT\n  DECOR\n  CAKE\n  ATTIRE\n  VENUE\n  OFFICIANT\n  HAIR_MAKEUP\n  ENTERTAINMENT\n  SECURITY\n  OTHER\n}\n\nenum VendorStatus {\n  ENQUIRED\n  QUOTED\n  BOOKED\n  CONFIRMED\n  CANCELLED\n  COMPLETED\n}\n\n// ─── Payments ─────────────────────────────────────────────────────────────────\n\nmodel Payment {\n  id                String        @id @default(uuid())\n  weddingId         String\n  eventId           String?\n  vendorId          String?\n  contributionId    String?\n  budgetLineId      String?\n  mpesaRef          String?       @unique\n  checkoutRequestId String?       @unique\n  idempotencyKey    String        @unique\n  amount            Decimal\n  currency          String        @default(\"KES\")\n  status            PaymentStatus @default(PENDING)\n  payerName         String?\n  payerPhone        String?\n  description       String?\n  paymentDate       DateTime?\n  rawCallback       Json?\n  processedAt       DateTime?\n  reconciledAt      DateTime?\n\n  version   Int       @default(1)\n  createdBy String?\n  deletedAt DateTime?\n\n  wedding      Wedding                @relation(fields: [weddingId], references: [id], onDelete: Cascade)\n  event        WeddingEvent?          @relation(fields: [eventId], references: [id], onDelete: SetNull)\n  vendor       Vendor?                @relation(fields: [vendorId], references: [id])\n  contribution CommitteeContribution? @relation(fields: [contributionId], references: [id])\n  budgetLine   BudgetLine?            @relation(fields: [budgetLineId], references: [id], onDelete: SetNull)\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([weddingId, createdAt])\n  @@index([weddingId, status])\n  @@index([vendorId])\n  @@index([eventId])\n  @@index([budgetLineId])\n}\n\nenum PaymentStatus {\n  PENDING\n  COMPLETED\n  FAILED\n  DUPLICATE\n  DISPUTED\n  REFUNDED\n}\n\n// ─── Committee Contributions ──────────────────────────────────────────────────\n\nmodel CommitteeContribution {\n  id           String        @id @default(uuid())\n  weddingId    String\n  eventId      String?\n  memberId     String\n  memberName   String\n  pledgeAmount Decimal\n  paidAmount   Decimal       @default(0)\n  pledgeDate   DateTime      @default(now())\n  dueDate      DateTime?\n  status       ContribStatus @default(PLEDGED)\n  notes        String?\n  payments     Payment[]\n\n  wedding Wedding       @relation(fields: [weddingId], references: [id], onDelete: Cascade)\n  event   WeddingEvent? @relation(fields: [eventId], references: [id], onDelete: SetNull)\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([weddingId, status])\n  @@index([memberId, weddingId])\n  @@index([eventId])\n}\n\nenum ContribStatus {\n  PLEDGED\n  PARTIAL\n  FULFILLED\n  OVERDUE\n  CANCELLED\n}\n\n// Timeline scheduling replaced by EventProgramItem (day-of program per event)\n// and event-scoped ChecklistItem tasks. TimelineEvent model removed.\n\n// ─── Checklist ────────────────────────────────────────────────────────────────\n\nmodel ChecklistItem {\n  id              String    @id @default(uuid())\n  weddingId       String\n  eventId         String?\n  title           String\n  description     String?\n  category        String?\n  activityGroupId String?\n  dueDate         DateTime?\n  assignedTo      String?\n  assignedToName  String?\n  dependsOnId     String?\n  isChecked       Boolean   @default(false)\n  checkedAt       DateTime?\n  checkedBy       String?\n  priority        Int       @default(2)\n  order           Int       @default(0)\n  isFinalCheck    Boolean   @default(false)\n  isPrivate       Boolean   @default(false)\n\n  version   Int       @default(1)\n  checksum  String    @default(\"\")\n  updatedBy String?\n  deletedAt DateTime?\n\n  wedding       Wedding        @relation(fields: [weddingId], references: [id], onDelete: Cascade)\n  event         WeddingEvent?  @relation(fields: [eventId], references: [id])\n  activityGroup ActivityGroup? @relation(fields: [activityGroupId], references: [id])\n  reminders     Reminder[]\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([weddingId, isChecked])\n  @@index([weddingId, dueDate])\n  @@index([weddingId, category])\n  @@index([activityGroupId])\n  @@index([eventId])\n}\n\n// ─── Activity Groups ──────────────────────────────────────────────────────────\n\nmodel ActivityGroup {\n  id             String          @id @default(uuid())\n  weddingId      String\n  name           String\n  color          String          @default(\"#8B5CF6\")\n  order          Int             @default(0)\n  wedding        Wedding         @relation(fields: [weddingId], references: [id], onDelete: Cascade)\n  checklistItems ChecklistItem[]\n\n  @@index([weddingId])\n}\n\n// ─── Budget Lines ─────────────────────────────────────────────────────────────\n\nmodel BudgetLine {\n  id           String    @id @default(uuid())\n  weddingId    String\n  eventId      String?\n  category     String\n  description  String\n  estimated    Decimal   @default(0)\n  actual       Decimal   @default(0)\n  committed    Decimal   @default(0)\n  vendorId     String?\n  vendorName   String?\n  notes        String?\n  paymentDate  DateTime?\n  reminderDate DateTime?\n  paymentPlan  String?\n  paymentType  String?\n\n  version   Int       @default(1)\n  checksum  String    @default(\"\")\n  updatedBy String?\n  deletedAt DateTime?\n\n  wedding  Wedding       @relation(fields: [weddingId], references: [id], onDelete: Cascade)\n  event    WeddingEvent? @relation(fields: [eventId], references: [id])\n  vendor   Vendor?       @relation(fields: [vendorId], references: [id])\n  payments Payment[]\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([weddingId, category])\n  @@index([eventId])\n  @@index([vendorId])\n}\n\n// ─── Risk Alerts ──────────────────────────────────────────────────────────────\n\nmodel RiskAlert {\n  id         String       @id @default(uuid())\n  weddingId  String\n  ruleId     String\n  severity   RiskSeverity\n  category   String\n  message    String\n  data       Json?\n  isResolved Boolean      @default(false)\n  resolvedAt DateTime?\n  resolvedBy String?\n\n  wedding Wedding @relation(fields: [weddingId], references: [id], onDelete: Cascade)\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([weddingId, isResolved])\n  @@index([weddingId, severity])\n}\n\nenum RiskSeverity {\n  CRITICAL\n  HIGH\n  MEDIUM\n  LOW\n}\n\n// ─── Media Items ──────────────────────────────────────────────────────────────\n\nmodel MediaItem {\n  id           String    @id @default(uuid())\n  weddingId    String\n  eventId      String?\n  title        String?\n  bucket       String\n  path         String\n  mimeType     String\n  sizeBytes    Int?\n  linkedToId   String?\n  linkedToType String?\n  uploadedBy   String?\n  deletedAt    DateTime?\n\n  wedding Wedding       @relation(fields: [weddingId], references: [id], onDelete: Cascade)\n  event   WeddingEvent? @relation(fields: [eventId], references: [id], onDelete: SetNull)\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([weddingId, createdAt])\n  @@index([linkedToId, linkedToType])\n  @@index([eventId])\n}\n\n// ─── Idempotency + Audit ──────────────────────────────────────────────────────\n\nmodel ProcessedOperation {\n  operationId    String   @id\n  processedAt    DateTime @default(now())\n  resultCode     Int      @default(200)\n  resultServerId String?\n  resultVersion  Int?\n\n  @@index([processedAt])\n}\n\nmodel AuditLog {\n  id           String   @id @default(uuid())\n  weddingId    String\n  actorId      String\n  actorRole    String\n  action       String\n  resourceId   String\n  resourceType String\n  ipAddress    String?\n  prevState    String?\n  nextState    String?\n  createdAt    DateTime @default(now())\n\n  wedding Wedding @relation(fields: [weddingId], references: [id], onDelete: Cascade)\n\n  @@index([weddingId, createdAt])\n  @@index([resourceId, resourceType])\n}\n\n// ─── Appointments ─────────────────────────────────────────────────────────────\n\nmodel Appointment {\n  id          String            @id @default(uuid())\n  weddingId   String\n  eventId     String?\n  title       String\n  description String?\n  vendorId    String?\n  location    String?\n  mapUrl      String?\n  startAt     DateTime\n  endAt       DateTime?\n  reminderAt  DateTime?\n  status      AppointmentStatus @default(SCHEDULED)\n  notes       String?\n  createdBy   String\n\n  wedding   Wedding       @relation(fields: [weddingId], references: [id], onDelete: Cascade)\n  event     WeddingEvent? @relation(fields: [eventId], references: [id], onDelete: SetNull)\n  vendor    Vendor?       @relation(fields: [vendorId], references: [id])\n  reminders Reminder[]\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([weddingId, startAt])\n  @@index([vendorId])\n  @@index([eventId])\n}\n\nenum AppointmentStatus {\n  SCHEDULED\n  COMPLETED\n  CANCELLED\n}\n\n// ─── Reminders ────────────────────────────────────────────────────────────────\n\nmodel Reminder {\n  id              String         @id @default(uuid())\n  checklistItemId String?\n  appointmentId   String?\n  triggerAt       DateTime\n  channel         String         @default(\"push\")\n  sent            Boolean        @default(false)\n  checklistItem   ChecklistItem? @relation(fields: [checklistItemId], references: [id], onDelete: Cascade)\n  appointment     Appointment?   @relation(fields: [appointmentId], references: [id], onDelete: Cascade)\n\n  @@index([triggerAt, sent])\n}\n\n// ─── Incidents ────────────────────────────────────────────────────────────────\n\nmodel Incident {\n  id          String         @id @default(uuid())\n  weddingId   String\n  eventId     String?\n  reportedAt  DateTime       @default(now())\n  description String\n  severity    String\n  resolvedAt  DateTime?\n  resolvedBy  String?\n  resolution  String?\n  notes       IncidentNote[]\n  wedding     Wedding        @relation(fields: [weddingId], references: [id], onDelete: Cascade)\n  event       WeddingEvent?  @relation(fields: [eventId], references: [id], onDelete: SetNull)\n\n  @@index([weddingId])\n  @@index([eventId])\n}\n\nmodel IncidentNote {\n  id         String   @id @default(uuid())\n  incidentId String\n  content    String\n  createdBy  String?\n  createdAt  DateTime @default(now())\n  incident   Incident @relation(fields: [incidentId], references: [id], onDelete: Cascade)\n\n  @@index([incidentId])\n}\n\n// ─── Templates ────────────────────────────────────────────────────────────────\n\nmodel Template {\n  id           String                @id @default(uuid())\n  type         TemplateType\n  name         String\n  culturalType CulturalType?\n  guestSizeMin Int?\n  guestSizeMax Int?\n  data         Json\n  isSystem     Boolean               @default(true)\n  applications TemplateApplication[]\n  createdAt    DateTime              @default(now())\n}\n\nmodel TemplateApplication {\n  id         String   @id @default(uuid())\n  weddingId  String\n  templateId String\n  appliedAt  DateTime @default(now())\n  wedding    Wedding  @relation(fields: [weddingId], references: [id], onDelete: Cascade)\n  template   Template @relation(fields: [templateId], references: [id])\n\n  @@index([weddingId])\n}\n\nenum TemplateType {\n  CHECKLIST\n  BUDGET\n  TIMELINE\n  VENDOR_LIST\n  APPOINTMENT\n  ACTIVITY_GROUP\n  GUEST_TAGS\n  PHOTOGRAPHY\n  SHOT_LIST\n}\n\n// ─── Dowry Items ──────────────────────────────────────────────────────────────\n\nmodel DowryItem {\n  id             String      @id @default(uuid())\n  weddingId      String\n  name           String\n  quantity       Int         @default(1)\n  estimatedValue Decimal?\n  agreedValue    Decimal?\n  status         DowryStatus @default(PENDING)\n  notes          String?\n  wedding        Wedding     @relation(fields: [weddingId], references: [id], onDelete: Cascade)\n  createdAt      DateTime    @default(now())\n  updatedAt      DateTime    @updatedAt\n\n  @@index([weddingId])\n}\n\nenum DowryStatus {\n  PENDING\n  AGREED\n  DELIVERED\n}\n\n// ─── Attire Items ─────────────────────────────────────────────────────────────\n\nmodel AttireItem {\n  id             String    @id @default(uuid())\n  weddingId      String\n  person         String\n  description    String\n  fabricSource   String?\n  tailorVendorId String?\n  fittingDate    DateTime?\n  status         String    @default(\"PENDING\")\n  wedding        Wedding   @relation(fields: [weddingId], references: [id], onDelete: Cascade)\n  tailor         Vendor?   @relation(fields: [tailorVendorId], references: [id])\n  createdAt      DateTime  @default(now())\n  updatedAt      DateTime  @updatedAt\n\n  @@index([weddingId])\n}\n\n// ─── Gift Registry ────────────────────────────────────────────────────────────\n\nmodel GiftRegistryItem {\n  id             String        @id @default(uuid())\n  weddingId      String\n  eventId        String?\n  name           String\n  description    String?\n  url            String?\n  estimatedPrice Decimal?\n  quantity       Int           @default(1)\n  priority       Int           @default(2)\n  wedding        Wedding       @relation(fields: [weddingId], references: [id], onDelete: Cascade)\n  event          WeddingEvent? @relation(fields: [eventId], references: [id], onDelete: SetNull)\n  createdAt      DateTime      @default(now())\n  updatedAt      DateTime      @updatedAt\n\n  @@index([weddingId])\n  @@index([eventId])\n}\n\nmodel GiftReceived {\n  id             String           @id @default(uuid())\n  weddingId      String\n  eventId        String?\n  guestId        String?\n  giverName      String?\n  giverPhone     String?\n  description    String\n  estimatedValue Decimal?\n  status         GiftStatus       @default(RECEIVED)\n  disposition    GiftDisposition?\n  receivedAt     DateTime         @default(now())\n  thankYouSent   Boolean          @default(false)\n  thankYouSentAt DateTime?\n  wedding        Wedding          @relation(fields: [weddingId], references: [id], onDelete: Cascade)\n  event          WeddingEvent?    @relation(fields: [eventId], references: [id], onDelete: SetNull)\n  guest          Guest?           @relation(fields: [guestId], references: [id])\n  createdAt      DateTime         @default(now())\n  updatedAt      DateTime         @updatedAt\n\n  @@index([weddingId])\n  @@index([eventId])\n}\n\nenum GiftStatus {\n  RECEIVED\n  THANKED\n  RETURNED\n}\n\nenum GiftDisposition {\n  KEEP\n  SELL\n  GIVE\n}\n\n// ─── Logistics & Transport ────────────────────────────────────────────────────\n\nmodel TransportRoute {\n  id                String           @id @default(uuid())\n  weddingId         String\n  eventId           String?\n  name              String\n  departureLocation String\n  arrivalLocation   String\n  departureTime     DateTime\n  capacity          Int?\n  assignedVendorId  String?\n  contactPerson     String?\n  contactPhone      String?\n  isCompleted       Boolean          @default(false)\n  wedding           Wedding          @relation(fields: [weddingId], references: [id], onDelete: Cascade)\n  event             WeddingEvent?    @relation(fields: [eventId], references: [id], onDelete: SetNull)\n  assignedVendor    Vendor?          @relation(fields: [assignedVendorId], references: [id])\n  guestTransports   GuestTransport[]\n  createdAt         DateTime         @default(now())\n\n  @@index([weddingId])\n  @@index([eventId])\n}\n\nmodel GuestTransport {\n  id      String         @id @default(uuid())\n  guestId String\n  routeId String\n  guest   Guest          @relation(fields: [guestId], references: [id], onDelete: Cascade)\n  route   TransportRoute @relation(fields: [routeId], references: [id], onDelete: Cascade)\n\n  @@unique([guestId, routeId])\n}\n\nmodel Accommodation {\n  id                  String               @id @default(uuid())\n  weddingId           String\n  eventId             String?\n  hotelName           String\n  address             String?\n  checkIn             DateTime\n  checkOut            DateTime\n  roomsBlocked        Int?\n  notes               String?\n  contactPerson       String?\n  contactPhone        String?\n  isCompleted         Boolean              @default(false)\n  wedding             Wedding              @relation(fields: [weddingId], references: [id], onDelete: Cascade)\n  event               WeddingEvent?        @relation(fields: [eventId], references: [id], onDelete: SetNull)\n  guestAccommodations GuestAccommodation[]\n  createdAt           DateTime             @default(now())\n\n  @@index([weddingId])\n  @@index([eventId])\n}\n\nmodel GuestAccommodation {\n  id              String        @id @default(uuid())\n  guestId         String\n  accommodationId String\n  roomNumber      String?\n  guest           Guest         @relation(fields: [guestId], references: [id], onDelete: Cascade)\n  accommodation   Accommodation @relation(fields: [accommodationId], references: [id], onDelete: Cascade)\n\n  @@unique([guestId, accommodationId])\n}\n\n// ─── Honeymoon ────────────────────────────────────────────────────────────────\n\nmodel HoneymoonDay {\n  id          String       @id @default(uuid())\n  eventId     String\n  date        DateTime\n  title       String\n  description String?\n  location    String?\n  mapUrl      String?\n  event       WeddingEvent @relation(fields: [eventId], references: [id], onDelete: Cascade)\n  createdAt   DateTime     @default(now())\n\n  @@index([eventId])\n}\n\n// ─── Vision Board Categories ──────────────────────────────────────────────────\n\nmodel VisionBoardCategory {\n  id        String   @id @default(uuid())\n  weddingId String\n  name      String\n  color     String   @default(\"#8B5CF6\")\n  order     Int      @default(0)\n  isDefault Boolean  @default(false)\n  wedding   Wedding  @relation(fields: [weddingId], references: [id], onDelete: Cascade)\n  createdAt DateTime @default(now())\n\n  @@unique([weddingId, name])\n  @@index([weddingId, order])\n}\n"
}

